// Node: "Validate Verify Token"
// Purpose: Confirms the request is genuinely from Meta

const VERIFY_TOKEN = "clickin360_secure_token_2025"; // CHANGE THIS — store in n8n credentials ideally

const query = $input.first().json.query || {};
const mode = query["hub.mode"];
const token = query["hub.verify_token"];
const challenge = query["hub.challenge"];

// Log the attempt
console.log("Meta verification attempt:", { mode, token: token ? "***" : "missing", challenge });

if (mode === "subscribe" && token === VERIFY_TOKEN) {
  // Valid — return challenge to confirm
  return [{
    json: {
      challenge: challenge,
      status: "verified",
      timestamp: new Date().toISOString()
    }
  }];
} else {
  // Invalid — return 403
  throw new Error(`Verification failed: invalid token or mode. Mode: ${mode}`);
};

// Node: "Filter Event Type" — Mode: Run Once for All Items
// Purpose: Filter WhatsApp events; parse raw body if Raw Body is enabled

const webhookData = $('Post Hook Whatsapp').first().json;

// === GET BODY (handles multiple n8n storage formats) ===
let body = webhookData?.body;

// If body is missing/empty, try rawBody
if (!body || (typeof body === 'object' && Object.keys(body).length === 0)) {
  let rawBody = webhookData?.rawBody;

  // Handle Buffer-like object
  if (rawBody && typeof rawBody === 'object') {
    if (rawBody.type === 'Buffer' && Array.isArray(rawBody.data)) {
      rawBody = Buffer.from(rawBody.data).toString('utf8');
    } else if (Buffer.isBuffer(rawBody)) {
      rawBody = rawBody.toString('utf8');
    }
  }

  // Parse string to JSON
  if (typeof rawBody === 'string') {
    try {
      body = JSON.parse(rawBody);
    } catch (e) {
      console.error("❌ Failed to parse rawBody as JSON:", e.message);
      return [];
    }
  }
}

// Last resort: check binary data
if (!body) {
  const binary = $('Post Hook Whatsapp').first().binary;
  if (binary?.data?.data) {
    try {
      const decoded = Buffer.from(binary.data.data, 'base64').toString('utf8');
      body = JSON.parse(decoded);
    } catch (e) {
      console.error("❌ Failed to decode binary:", e.message);
    }
  }
}

if (!body) {
  console.error("❌ Could not find webhook body in any format");
  console.error("Available keys:", Object.keys(webhookData || {}));
  return [];
}

// === EXTRACT MESSAGE ===
const value = body?.entry?.[0]?.changes?.[0]?.value;

if (!value) {
  console.warn("⚠️ No value in payload — skipping");
  return [];
}

const hasMessages = Array.isArray(value.messages) && value.messages.length > 0;
const hasStatuses = Array.isArray(value.statuses) && value.statuses.length > 0;

if (hasStatuses && !hasMessages) {
  console.log("📊 Status update event — skipping");
  return [];
}

if (!hasMessages) {
  console.warn("⚠️ Unknown event type — skipping");
  return [];
}

const message = value.messages[0];
console.log(`✅ Valid message: type=${message.type}, from=${message.from}`);

// === RETURN CLEAN STRUCTURE ===
return [{
  json: {
    validated: true,
    message_type: message.type,
    phone_number: message.from,
    message_id: message.id,
    timestamp: message.timestamp,
    text_content: message.text?.body || null,
    raw_body: body  // Pass parsed body for downstream nodes
  }
}];

// Node: "Validate Meta Signature" — Mode: Run Once for All Items
// Purpose: Verify HMAC-SHA256 signature from Meta against raw body

const crypto = require('crypto');

// === CONFIG ===
const APP_SECRET = "62c3d37026ddc99be48a12e03cce36be"; // ← Make sure this is set!

// === GET WEBHOOK DATA ===
const webhookItem = $('Post Hook Whatsapp').first().json;
const headers = webhookItem.headers || {};
const receivedSignature = headers["x-hub-signature-256"];

// === DEV MODE: Skip if no signature ===
if (!receivedSignature) {
  console.warn("⚠️ No x-hub-signature-256 header — skipping validation");
  return [{ json: { validated: false, skipped: true, reason: "no_header" } }];
}

// === GET RAW BODY (multiple formats) ===
let rawBody = webhookItem.rawBody;

// Handle Buffer-like object
if (rawBody && typeof rawBody === 'object') {
  if (rawBody.type === 'Buffer' && Array.isArray(rawBody.data)) {
    rawBody = Buffer.from(rawBody.data).toString('utf8');
  } else if (Buffer.isBuffer(rawBody)) {
    rawBody = rawBody.toString('utf8');
  }
}

// Try binary if rawBody not available
if (!rawBody || typeof rawBody !== 'string') {
  const binary = $('Post Hook Whatsapp').first().binary;
  if (binary?.data?.data) {
    rawBody = Buffer.from(binary.data.data, 'base64').toString('utf8');
  }
}

if (!rawBody || typeof rawBody !== 'string') {
  console.error("❌ Could not find raw body in any format");
  console.error("webhookItem keys:", Object.keys(webhookItem));
  throw new Error("Raw body unavailable for signature validation");
}

// === COMPUTE HMAC ===
const computedSignature = "sha256=" + crypto
  .createHmac("sha256", APP_SECRET)
  .update(rawBody)
  .digest("hex");

// === COMPARE ===
if (receivedSignature !== computedSignature) {
  console.error("❌ Signature mismatch");
  console.error("Computed:", computedSignature);
  console.error("Received:", receivedSignature);
  console.error("Body length:", rawBody.length);
  console.error("Body preview:", rawBody.substring(0, 200));
  throw new Error("Invalid Meta signature — request rejected");
}

console.log("✅ Signature validated");
return [{ json: { validated: true } }];

